#include <bits/stdc++.h>
using namespace std;vector<int>g[1001];bool vis[1001];string o;
void dfs(int u){vis[u]=1;o+=to_string(u)+" ";for(int v:g[u])if(!vis[v])dfs(v);}
int main(){int n,m,v;cin>>n>>m>>v;for(int i=0;i<m;i++){int a,b;cin>>a>>b;g[a].push_back(b);g[b].push_back(a);}for(int i=1;i<=n;i++)sort(g[i].begin(),g[i].end());dfs(v);if(!o.empty())o.pop_back();cout<<o<<"\n";memset(vis,0,sizeof vis);string b;queue<int>q;q.push(v);vis[v]=1;while(!q.empty()){int u=q.front();q.pop();b+=to_string(u)+" ";for(int w:g[u])if(!vis[w]){vis[w]=1;q.push(w);}}if(!b.empty())b.pop_back();cout<<b<<"\n";}
